import type { Element } from '@bim-ai/core';

import type { PlanProjectionPrimitivesV1Wire } from '../../plan/planProjectionWire';

type GridLinePrim = {
  id: string;
  levelId?: string | null;
};

function readGridLines(primitives: PlanProjectionPrimitivesV1Wire | null): GridLinePrim[] {
  if (!primitives || typeof primitives !== 'object') return [];
  const raw = (primitives as Record<string, unknown>).gridLines;
  if (!Array.isArray(raw)) return [];
  const out: GridLinePrim[] = [];
  for (const row of raw) {
    if (!row || typeof row !== 'object') continue;
    const o = row as Record<string, unknown>;
    if (typeof o.id !== 'string') continue;
    const lid = o.levelId ?? o.level_id;
    out.push({
      id: o.id,
      levelId: lid == null || lid === '' ? null : String(lid),
    });
  }
  return out;
}

/** Compact inspector line: grid ids on wire + datum reference sanity vs snapshot levels. */
export function buildPlanGridDatumInspectorLine(
  elementsById: Record<string, Element>,
  planProjectionPrimitives: PlanProjectionPrimitivesV1Wire | null,
  planViewId: string,
): string {
  const pv = elementsById[planViewId];
  if (!pv || pv.kind !== 'plan_view') return '';
  const grids = readGridLines(planProjectionPrimitives);
  if (!grids.length) return '';
  const sorted = [...grids].sort((a, b) => a.id.localeCompare(b.id));
  let bad = 0;
  const tok = sorted
    .map((g) => {
      if (!g.levelId) return `${g.id}:noLevel`;
      const host = elementsById[g.levelId];
      if (!host || host.kind !== 'level') {
        bad += 1;
        return `${g.id}:datum_grid_reference_missing`;
      }
      return `${g.id}:ok`;
    })
    .join(';');
  return `planGridDatum grids=${sorted.length} badRef=${bad} ${tok}`;
}
export type LevelDatumPropagationRowV0 = {
  levelId: string;
  elevationBeforeMm: number;
  elevationAfterMm: number;
  deltaMm: number;
  parentLevelId: string | null;
  role: 'direct_move' | 'datum_propagated' | 'unchanged';
};

export type LevelElevationPropagationEvidenceV0 = {
  format: 'levelElevationPropagationEvidence_v0';
  datumPropagationBlocked: boolean;
  directMoveLevelIds?: string[];
  rows: LevelDatumPropagationRowV0[];
};

function isRow(x: unknown): x is LevelDatumPropagationRowV0 {
  if (!x || typeof x !== 'object') return false;
  const o = x as Record<string, unknown>;
  if (typeof o.levelId !== 'string') return false;
  if (typeof o.role !== 'string') return false;
  if (!['direct_move', 'datum_propagated', 'unchanged'].includes(o.role)) return false;
  return (
    typeof o.elevationBeforeMm === 'number' &&
    typeof o.elevationAfterMm === 'number' &&
    typeof o.deltaMm === 'number'
  );
}

export function parseLevelElevationPropagationEvidence(
  raw: unknown,
): LevelElevationPropagationEvidenceV0 | null {
  if (!raw || typeof raw !== 'object') return null;
  const o = raw as Record<string, unknown>;
  if (o.format !== 'levelElevationPropagationEvidence_v0') return null;
  if (typeof o.datumPropagationBlocked !== 'boolean') return null;
  const rowsRaw = o.rows;
  if (!Array.isArray(rowsRaw) || !rowsRaw.every(isRow)) return null;
  return {
    format: 'levelElevationPropagationEvidence_v0',
    datumPropagationBlocked: o.datumPropagationBlocked,
    directMoveLevelIds: Array.isArray(o.directMoveLevelIds)
      ? o.directMoveLevelIds.filter((x): x is string => typeof x === 'string')
      : undefined,
    rows: rowsRaw,
  };
}

/** Single monospace line for workbench / agents (stable sort by levelId). */
export function formatLevelDatumPropagationEvidenceLine(
  ev: LevelElevationPropagationEvidenceV0,
): string {
  const rows = [...ev.rows].sort((a, b) => a.levelId.localeCompare(b.levelId));
  const parts = rows.map((r) => `${r.levelId}:${r.role}:Δ${r.deltaMm.toFixed(3)}`);
  return `blocked=${ev.datumPropagationBlocked} ${parts.join('|')}`;
}
"""Deterministic evidence payload for level elevation moves + datum propagation."""

from __future__ import annotations

from typing import Any

from bim_ai.datum_levels import level_datum_topo_order_if_acyclic
from bim_ai.document import Document
from bim_ai.elements import LevelElem


def _move_level_targets_from_commands(commands: list[dict[str, Any]]) -> list[str]:
    moved: set[str] = set()
    for c in commands:
        if str(c.get("type") or "") != "moveLevelElevation":
            continue
        lid = c.get("levelId") or c.get("level_id")
        if isinstance(lid, str) and lid.strip():
            moved.add(lid.strip())
    return sorted(moved)


def build_level_elevation_propagation_evidence_v0(
    doc_before: Document,
    doc_after: Document,
    *,
    applied_commands: list[dict[str, Any]],
) -> dict[str, Any]:
    """Summarize per-level elevation deltas after one or more `moveLevelElevation` commits."""
    blocked = level_datum_topo_order_if_acyclic(doc_after.elements) is None
    direct_ids = set(_move_level_targets_from_commands(applied_commands))
    level_ids = sorted(lid for lid, el in doc_after.elements.items() if isinstance(el, LevelElem))
    rows: list[dict[str, Any]] = []
    for lid in level_ids:
        a_el = doc_after.elements.get(lid)
        if not isinstance(a_el, LevelElem):
            continue
        b_el = doc_before.elements.get(lid)
        before_mm = (
            float(b_el.elevation_mm) if isinstance(b_el, LevelElem) else float(a_el.elevation_mm)
        )
        after_mm = float(a_el.elevation_mm)
        delta_mm = round(after_mm - before_mm, 3)
        pid_raw = a_el.parent_level_id
        pid = str(pid_raw).strip() if pid_raw else None
        if pid == "":
            pid = None

        if lid in direct_ids:
            role = "direct_move"
        elif abs(delta_mm) >= 1e-6:
            role = "datum_propagated"
        else:
            role = "unchanged"

        rows.append(
            {
                "levelId": lid,
                "elevationBeforeMm": round(before_mm, 3),
                "elevationAfterMm": round(after_mm, 3),
                "deltaMm": delta_mm,
                "parentLevelId": pid,
                "role": role,
            }
        )

    return {
        "format": "levelElevationPropagationEvidence_v0",
        "datumPropagationBlocked": blocked,
        "directMoveLevelIds": sorted(direct_ids),
        "rows": rows,
    }

