export async function fetchSectionProjectionWire(
  modelId: string,
  sectionCutId: string,
): Promise<Record<string, unknown>> {
  const url = `/api/models/${encodeURIComponent(modelId)}/projection/section/${encodeURIComponent(sectionCutId)}`;
